solution: ```class Solution {
public:
    int maximumLengthSubstring(string s) {
        int cnt[26] = {0};
        int left = 0, maxLen = 0;
        for (int right = 0; right < s.size(); ++right) {
            int idx = s[right] - 'a';
            ++cnt[idx];
            while (cnt[idx] > 2) {
                --cnt[s[left] - 'a'];
                ++left;
            }
            maxLen = max(maxLen, right - left + 1);
        }
        return maxLen;
    }
};
